### Step 1: Write failing tests for new config types

#[test]
fn test_lite_config_roundtrip() {
    let config = CorviaConfig::default();
    config.save(Path::new("/tmp/corvia-test-lite.toml")).unwrap();
    let loaded = CorviaConfig::load(Path::new("/tmp/corvia-test-lite.toml")).unwrap();
    assert_eq!(loaded.storage.store_type, StoreType::Lite);
    assert_eq!(loaded.embedding.provider, InferenceProvider::Ollama);
}

#[test]
fn test_full_config_roundtrip() {
    let config = CorviaConfig::full_default();
    config.save(Path::new("/tmp/corvia-test-full.toml")).unwrap();
    let loaded = CorviaConfig::load(Path::new("/tmp/corvia-test-full.toml")).unwrap();
    assert_eq!(loaded.storage.store_type, StoreType::Surrealdb);
    assert_eq!(loaded.storage.surrealdb_url, Some("127.0.0.1:8000".into()));
}

#[test]
fn test_store_type_serde() {
    let json = serde_json::to_string(&StoreType::Lite).unwrap();
    assert_eq!(json, "\"lite\"");
    let parsed: StoreType = serde_json::from_str("\"surrealdb\"").unwrap();
    assert_eq!(parsed, StoreType::Surrealdb);
}
